#!/bin/bash

# =============================================================================
# PATHWAYS COMPLETE DEPLOYMENT AUTOMATION SCRIPT
# Run this script to deploy everything in one go
# Usage: bash setup.sh
# =============================================================================

set -e  # Exit on error

# Colors for output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
NC='\033[0m' # No Color

echo -e "${GREEN}"
echo "╔════════════════════════════════════════════════════════════════════╗"
echo "║       🚀 PATHWAYS PLATFORM COMPLETE DEPLOYMENT SCRIPT 🚀           ║"
echo "║                  Deploy in ~60 minutes                              ║"
echo "╚════════════════════════════════════════════════════════════════════╝"
echo -e "${NC}"

# =============================================================================
# STEP 1: CHECK PREREQUISITES
# =============================================================================
echo -e "${YELLOW}[STEP 1] Checking prerequisites...${NC}"

if ! command -v node &> /dev/null; then
    echo -e "${RED}❌ Node.js not found. Please install Node.js from nodejs.org${NC}"
        exit 1
        fi

        if ! command -v git &> /dev/null; then
            echo -e "${RED}❌ Git not found. Please install Git${NC}"
                exit 1
                fi

                echo -e "${GREEN}✅ Node.js and Git installed${NC}"
                echo ""

                # =============================================================================
                # STEP 2: GET USER INPUTS
                # =============================================================================
                echo -e "${YELLOW}[STEP 2] Getting your configuration...${NC}"
                echo ""

                read -p "Enter your GitHub username: " GITHUB_USERNAME
                read -p "Enter MongoDB connection string (from Atlas): " MONGODB_URI
                read -p "Enter a random JWT secret (min 32 chars, use randomkeygen.com): " JWT_SECRET
                read -p "Enter your email: " EMAIL
                read -p "Enter your name: " USER_NAME

                # Validate inputs
                if [ -z "$GITHUB_USERNAME" ] || [ -z "$MONGODB_URI" ] || [ -z "$JWT_SECRET" ]; then
                    echo -e "${RED}❌ Missing required inputs${NC}"
                        exit 1
                        fi

                        echo -e "${GREEN}✅ Configuration saved${NC}"
                        echo ""

                        # =============================================================================
                        # STEP 3: CREATE BACKEND FOLDER STRUCTURE
                        # =============================================================================
                        echo -e "${YELLOW}[STEP 3] Creating backend folder structure...${NC}"

                        mkdir -p pathways-api/{config,models,routes,middleware}
                        cd pathways-api

                        echo -e "${GREEN}✅ Folders created${NC}"
                        echo ""

                        # =============================================================================
                        # STEP 4: CREATE package.json
                        # =============================================================================
                        echo -e "${YELLOW}[STEP 4] Creating package.json...${NC}"

                        cat > package.json << 'EOF'
                        {
                          "name": "pathways-api",
                            "version": "1.0.0",
                              "description": "Backend API for Pathways learning platform",
                                "type": "module",
                                  "main": "server.js",
                                    "scripts": {
                                        "start": "node server.js",
                                            "dev": "nodemon server.js",
                                                "test": "echo \"Error: no test specified\" && exit 1"
                                                  },
                                                    "keywords": ["learning", "pathways", "api"],
                                                      "author": "Your Name",
                                                        "license": "MIT",
                                                          "dependencies": {
                                                              "express": "^4.18.2",
                                                                  "mongoose": "^7.6.3",
                                                                      "bcryptjs": "^2.4.3",
                                                                          "jsonwebtoken": "^9.1.0",
                                                                              "dotenv": "^16.3.1",
                                                                                  "cors": "^2.8.5",
                                                                                      "validator": "^13.11.0",
                                                                                          "express-validator": "^7.0.0"
                                                                                            },
                                                                                              "devDependencies": {
                                                                                                  "nodemon": "^3.0.1"
                                                                                                    }
                                                                                                    }
                                                                                                    EOF
                                                                                                    
                                                                                                    echo -e "${GREEN}✅ package.json created${NC}"
                                                                                                    echo ""
                                                                                                    
                                                                                                    # =============================================================================
                                                                                                    # STEP 5: CREATE .env FILE
                                                                                                    # =============================================================================
                                                                                                    echo -e "${YELLOW}[STEP 5] Creating .env file...${NC}"
                                                                                                    
                                                                                                    cat > .env << EOF
                                                                                                    PORT=5000
                                                                                                    MONGODB_URI=$MONGODB_URI
                                                                                                    JWT_SECRET=$JWT_SECRET
                                                                                                    JWT_EXPIRE=7d
                                                                                                    NODE_ENV=development
                                                                                                    CORS_ORIGIN=http://localhost:5173
                                                                                                    STRIPE_SECRET_KEY=sk_test_fake_for_now
                                                                                                    SMTP_EMAIL=$EMAIL
                                                                                                    SMTP_PASSWORD=app-password
                                                                                                    EOF
                                                                                                    
                                                                                                    echo -e "${GREEN}✅ .env file created${NC}"
                                                                                                    echo ""
                                                                                                    
                                                                                                    # =============================================================================
                                                                                                    # STEP 6: CREATE DATABASE CONFIG
                                                                                                    # =============================================================================
                                                                                                    echo -e "${YELLOW}[STEP 6] Creating database configuration...${NC}"
                                                                                                    
                                                                                                    cat > config/database.js << 'EOF'
                                                                                                    import mongoose from 'mongoose';
                                                                                                    
                                                                                                    const connectDB = async () => {
                                                                                                      try {
                                                                                                          await mongoose.connect(process.env.MONGODB_URI);
                                                                                                              console.log('✅ MongoDB connected successfully');
                                                                                                                } catch (error) {
                                                                                                                    console.error('❌ Database connection failed:', error.message);
                                                                                                                        process.exit(1);
                                                                                                                          }
                                                                                                                          };
                                                                                                                          
                                                                                                                          export default connectDB;
                                                                                                                          EOF
                                                                                                                          
                                                                                                                          echo -e "${GREEN}✅ Database config created${NC}"
                                                                                                                          echo ""
                                                                                                                          
                                                                                                                          # =============================================================================
                                                                                                                          # STEP 7: CREATE MODELS
                                                                                                                          # =============================================================================
                                                                                                                          echo -e "${YELLOW}[STEP 7] Creating database models...${NC}"
                                                                                                                          
                                                                                                                          # User Model
                                                                                                                          cat > models/User.js << 'EOF'
                                                                                                                          import mongoose from 'mongoose';
                                                                                                                          import bcryptjs from 'bcryptjs';
                                                                                                                          
                                                                                                                          const userSchema = new mongoose.Schema({
                                                                                                                            firstName: { type: String, required: true },
                                                                                                                              lastName: { type: String, required: true },
                                                                                                                                email: { type: String, required: true, unique: true, lowercase: true },
                                                                                                                                  password: { type: String, required: true, minlength: 6, select: false },
                                                                                                                                    avatar: String,
                                                                                                                                      bio: String,
                                                                                                                                        role: { type: String, enum: ['learner', 'educator', 'admin'], default: 'learner' },
                                                                                                                                          isEmailVerified: { type: Boolean, default: false },
                                                                                                                                            points: { type: Number, default: 0 },
                                                                                                                                              streak: { type: Number, default: 0 },
                                                                                                                                                lastLearningDate: Date,
                                                                                                                                                  enrolledPathways: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Pathway' }],
                                                                                                                                                    bookmarks: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Pathway' }],
                                                                                                                                                      createdAt: { type: Date, default: Date.now },
                                                                                                                                                        updatedAt: { type: Date, default: Date.now }
                                                                                                                                                        }, { timestamps: true });
                                                                                                                                                        
                                                                                                                                                        userSchema.pre('save', async function(next) {
                                                                                                                                                          if (!this.isModified('password')) return next();
                                                                                                                                                            this.password = await bcryptjs.hash(this.password, 10);
                                                                                                                                                              next();
                                                                                                                                                              });
                                                                                                                                                              
                                                                                                                                                              userSchema.methods.matchPassword = async function(password) {
                                                                                                                                                                return await bcryptjs.compare(password, this.password);
                                                                                                                                                                };
                                                                                                                                                                
                                                                                                                                                                const User = mongoose.model('User', userSchema);
                                                                                                                                                                export default User;
                                                                                                                                                                EOF
                                                                                                                                                                
                                                                                                                                                                # Pathway Model
                                                                                                                                                                cat > models/Pathway.js << 'EOF'
                                                                                                                                                                import mongoose from 'mongoose';
                                                                                                                                                                
                                                                                                                                                                const pathwaySchema = new mongoose.Schema({
                                                                                                                                                                  title: { type: String, required: true },
                                                                                                                                                                    description: String,
                                                                                                                                                                      category: String,
                                                                                                                                                                        level: { type: String, enum: ['Beginner', 'Intermediate', 'Advanced'] },
                                                                                                                                                                          duration: Number,
                                                                                                                                                                            price: { type: Number, default: 0 },
                                                                                                                                                                              instructor: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
                                                                                                                                                                                image: String,
                                                                                                                                                                                  rating: { type: Number, default: 0 },
                                                                                                                                                                                    modules: [{
                                                                                                                                                                                        title: String,
                                                                                                                                                                                            description: String,
                                                                                                                                                                                                content: String,
                                                                                                                                                                                                    resources: [{ title: String, url: String, type: String }]
                                                                                                                                                                                                      }],
                                                                                                                                                                                                        createdAt: { type: Date, default: Date.now }
                                                                                                                                                                                                        });
                                                                                                                                                                                                        
                                                                                                                                                                                                        const Pathway = mongoose.model('Pathway', pathwaySchema);
                                                                                                                                                                                                        export default Pathway;
                                                                                                                                                                                                        EOF
                                                                                                                                                                                                        
                                                                                                                                                                                                        # Progress Model
                                                                                                                                                                                                        cat > models/Progress.js << 'EOF'
                                                                                                                                                                                                        import mongoose from 'mongoose';
                                                                                                                                                                                                        
                                                                                                                                                                                                        const progressSchema = new mongoose.Schema({
                                                                                                                                                                                                          userId: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },
                                                                                                                                                                                                            pathwayId: { type: mongoose.Schema.Types.ObjectId, ref: 'Pathway', required: true },
                                                                                                                                                                                                              completedModules: [{ moduleId: String, completedAt: Date, timeSpent: Number }],
                                                                                                                                                                                                                overallProgress: { type: Number, default: 0 },
                                                                                                                                                                                                                  startDate: { type: Date, default: Date.now },
                                                                                                                                                                                                                    lastAccessDate: Date,
                                                                                                                                                                                                                      totalTimeSpent: { type: Number, default: 0 },
                                                                                                                                                                                                                        isCompleted: { type: Boolean, default: false },
                                                                                                                                                                                                                          completionDate: Date
                                                                                                                                                                                                                          });
                                                                                                                                                                                                                          
                                                                                                                                                                                                                          const Progress = mongoose.model('Progress', progressSchema);
                                                                                                                                                                                                                          export default Progress;
                                                                                                                                                                                                                          EOF
                                                                                                                                                                                                                          
                                                                                                                                                                                                                          echo -e "${GREEN}✅ Models created (User, Pathway, Progress)${NC}"
                                                                                                                                                                                                                          echo ""
                                                                                                                                                                                                                          
                                                                                                                                                                                                                          # =============================================================================
                                                                                                                                                                                                                          # STEP 8: CREATE MIDDLEWARE
                                                                                                                                                                                                                          # =============================================================================
                                                                                                                                                                                                                          echo -e "${YELLOW}[STEP 8] Creating middleware...${NC}"
                                                                                                                                                                                                                          
                                                                                                                                                                                                                          # Auth Middleware
                                                                                                                                                                                                                          cat > middleware/auth.js << 'EOF'
                                                                                                                                                                                                                          import jwt from 'jsonwebtoken';
                                                                                                                                                                                                                          
                                                                                                                                                                                                                          const authMiddleware = (req, res, next) => {
                                                                                                                                                                                                                            try {
                                                                                                                                                                                                                                const token = req.headers.authorization?.split(' ')[1];
                                                                                                                                                                                                                                    if (!token) return res.status(401).json({ message: 'No token provided' });
                                                                                                                                                                                                                                        const decoded = jwt.verify(token, process.env.JWT_SECRET);
                                                                                                                                                                                                                                            req.userId = decoded.userId;
                                                                                                                                                                                                                                                next();
                                                                                                                                                                                                                                                  } catch (error) {
                                                                                                                                                                                                                                                      res.status(401).json({ message: 'Invalid token' });
                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                        };
                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                        export default authMiddleware;
                                                                                                                                                                                                                                                        EOF
                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                        # Error Handler
                                                                                                                                                                                                                                                        cat > middleware/errorHandler.js << 'EOF'
                                                                                                                                                                                                                                                        const errorHandler = (err, req, res, next) => {
                                                                                                                                                                                                                                                          console.error(err.stack);
                                                                                                                                                                                                                                                            res.status(500).json({
                                                                                                                                                                                                                                                                message: err.message || 'Internal Server Error',
                                                                                                                                                                                                                                                                    error: process.env.NODE_ENV === 'development' ? err : {}
                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                      };
                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                      export default errorHandler;
                                                                                                                                                                                                                                                                      EOF
                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                      echo -e "${GREEN}✅ Middleware created${NC}"
                                                                                                                                                                                                                                                                      echo ""
                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                      # =============================================================================
                                                                                                                                                                                                                                                                      # STEP 9: CREATE ROUTES
                                                                                                                                                                                                                                                                      # =============================================================================
                                                                                                                                                                                                                                                                      echo -e "${YELLOW}[STEP 9] Creating API routes...${NC}"
                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                      # Auth Routes
                                                                                                                                                                                                                                                                      cat > routes/auth.js << 'EOF'
                                                                                                                                                                                                                                                                      import express from 'express';
                                                                                                                                                                                                                                                                      import User from '../models/User.js';
                                                                                                                                                                                                                                                                      import jwt from 'jsonwebtoken';
                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                      const router = express.Router();
                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                      router.post('/register', async (req, res) => {
                                                                                                                                                                                                                                                                        try {
                                                                                                                                                                                                                                                                            const { firstName, lastName, email, password } = req.body;
                                                                                                                                                                                                                                                                                if (!firstName || !lastName || !email || !password) {
                                                                                                                                                                                                                                                                                      return res.status(400).json({ message: 'All fields are required' });
                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                              const existingUser = await User.findOne({ email });
                                                                                                                                                                                                                                                                                                  if (existingUser) {
                                                                                                                                                                                                                                                                                                        return res.status(400).json({ message: 'Email already in use' });
                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                const user = new User({ firstName, lastName, email, password });
                                                                                                                                                                                                                                                                                                                    await user.save();
                                                                                                                                                                                                                                                                                                                        const token = jwt.sign({ userId: user._id }, process.env.JWT_SECRET, { expiresIn: process.env.JWT_EXPIRE });
                                                                                                                                                                                                                                                                                                                            res.status(201).json({
                                                                                                                                                                                                                                                                                                                                  message: 'User registered successfully',
                                                                                                                                                                                                                                                                                                                                        token,
                                                                                                                                                                                                                                                                                                                                              user: { _id: user._id, firstName: user.firstName, lastName: user.lastName, email: user.email, role: user.role }
                                                                                                                                                                                                                                                                                                                                                  });
                                                                                                                                                                                                                                                                                                                                                    } catch (error) {
                                                                                                                                                                                                                                                                                                                                                        res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                          router.post('/login', async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                            try {
                                                                                                                                                                                                                                                                                                                                                                const { email, password } = req.body;
                                                                                                                                                                                                                                                                                                                                                                    if (!email || !password) {
                                                                                                                                                                                                                                                                                                                                                                          return res.status(400).json({ message: 'Email and password required' });
                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                  const user = await User.findOne({ email }).select('+password');
                                                                                                                                                                                                                                                                                                                                                                                      if (!user || !(await user.matchPassword(password))) {
                                                                                                                                                                                                                                                                                                                                                                                            return res.status(401).json({ message: 'Invalid credentials' });
                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                    const token = jwt.sign({ userId: user._id }, process.env.JWT_SECRET, { expiresIn: process.env.JWT_EXPIRE });
                                                                                                                                                                                                                                                                                                                                                                                                        res.json({
                                                                                                                                                                                                                                                                                                                                                                                                              message: 'Login successful',
                                                                                                                                                                                                                                                                                                                                                                                                                    token,
                                                                                                                                                                                                                                                                                                                                                                                                                          user: { _id: user._id, firstName: user.firstName, lastName: user.lastName, email: user.email, role: user.role, avatar: user.avatar }
                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                    res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                      export default router;
                                                                                                                                                                                                                                                                                                                                                                                                                                      EOF
                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                      # Progress Routes
                                                                                                                                                                                                                                                                                                                                                                                                                                      cat > routes/progress.js << 'EOF'
                                                                                                                                                                                                                                                                                                                                                                                                                                      import express from 'express';
                                                                                                                                                                                                                                                                                                                                                                                                                                      import Progress from '../models/Progress.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                      import User from '../models/User.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                      import authMiddleware from '../middleware/auth.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                      const router = express.Router();
                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                      router.post('/module-complete', authMiddleware, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                        try {
                                                                                                                                                                                                                                                                                                                                                                                                                                            const { pathwayId, moduleId, timeSpent } = req.body;
                                                                                                                                                                                                                                                                                                                                                                                                                                                const userId = req.userId;
                                                                                                                                                                                                                                                                                                                                                                                                                                                    let progress = await Progress.findOne({ userId, pathwayId });
                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (!progress) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                              progress = new Progress({ userId, pathwayId, completedModules: [{ moduleId, completedAt: new Date(), timeSpent }], totalTimeSpent: timeSpent });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        progress.completedModules.push({ moduleId, completedAt: new Date(), timeSpent });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              progress.totalTimeSpent += timeSpent;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      progress.overallProgress = Math.round((progress.completedModules.length / 10) * 100);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          progress.lastAccessDate = new Date();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              await progress.save();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const user = await User.findById(userId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      user.points += Math.ceil(timeSpent / 60);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          await user.save();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              res.json({ message: 'Module completion recorded', progress, pointsEarned: Math.ceil(timeSpent / 60) });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      router.get('/statistics/:userId', authMiddleware, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const { userId } = req.params;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const user = await User.findById(userId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const pathwaysEnrolled = await Progress.countDocuments({ userId });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const pathwaysCompleted = await Progress.countDocuments({ userId, isCompleted: true });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            res.json({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  user: { firstName: user.firstName, lastName: user.lastName, points: user.points, streak: user.streak, avatar: user.avatar },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        stats: { pathwaysEnrolled, pathwaysCompleted, completionRate: Math.round((pathwaysCompleted / pathwaysEnrolled) * 100) }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    export default router;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    EOF
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    # Search Routes
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cat > routes/search.js << 'EOF'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    import express from 'express';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    import Pathway from '../models/Pathway.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    import authMiddleware from '../middleware/auth.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const router = express.Router();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    router.get('/', authMiddleware, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const { q, category, level } = req.query;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              let query = {};
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (q) query.title = { $regex: q, $options: 'i' };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (category) query.category = category;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (level) query.level = level;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const pathways = await Pathway.find(query).limit(20);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  res.json({ pathways });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          router.get('/trending', authMiddleware, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const pathways = await Pathway.find().sort({ rating: -1 }).limit(10);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    res.json({ pathways });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            export default router;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            EOF
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            # Users Routes
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            cat > routes/users.js << 'EOF'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            import express from 'express';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            import User from '../models/User.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            import authMiddleware from '../middleware/auth.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const router = express.Router();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            router.get('/:id', authMiddleware, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const user = await User.findById(req.params.id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (!user) return res.status(404).json({ message: 'User not found' });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          res.json({ user });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  router.put('/:id', authMiddleware, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const user = await User.findByIdAndUpdate(req.params.id, req.body, { new: true });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            res.json({ user });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    export default router;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    EOF
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    # Pathways Routes
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cat > routes/pathways.js << 'EOF'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    import express from 'express';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    import Pathway from '../models/Pathway.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    import authMiddleware from '../middleware/auth.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const router = express.Router();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    router.get('/', authMiddleware, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const pathways = await Pathway.find().limit(20);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              res.json({ pathways });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      router.get('/:id', authMiddleware, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const pathway = await Pathway.findById(req.params.id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                res.json({ pathway });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        export default router;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        EOF
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Reviews Routes
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        cat > routes/reviews.js << 'EOF'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        import express from 'express';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        import authMiddleware from '../middleware/auth.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const router = express.Router();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        router.get('/pathway/:pathwayId', authMiddleware, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              res.json({ reviews: [] });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    res.status(500).json({ message: error.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      export default router;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      EOF
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      echo -e "${GREEN}✅ All routes created${NC}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      echo ""
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      # =============================================================================
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      # STEP 10: CREATE MAIN SERVER
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      # =============================================================================
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      echo -e "${YELLOW}[STEP 10] Creating main server file...${NC}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      cat > server.js << 'EOF'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import express from 'express';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import cors from 'cors';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import dotenv from 'dotenv';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import connectDB from './config/database.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import authRoutes from './routes/auth.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import userRoutes from './routes/users.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import pathwayRoutes from './routes/pathways.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import progressRoutes from './routes/progress.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import searchRoutes from './routes/search.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import reviewRoutes from './routes/reviews.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      import errorHandler from './middleware/errorHandler.js';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      dotenv.config();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const app = express();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      connectDB();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      app.use(express.json());
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      app.use(express.urlencoded({ extended: true }));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      app.use(cors({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        origin: process.env.CORS_ORIGIN || 'http://localhost:5173',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          credentials: true
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          app.use('/api/auth', authRoutes);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          app.use('/api/users', userRoutes);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          app.use('/api/pathways', pathwayRoutes);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          app.use('/api/progress', progressRoutes);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          app.use('/api/search', searchRoutes);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          app.use('/api/reviews', reviewRoutes);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          app.get('/api/health', (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            res.json({ status: 'API is running ✅', timestamp: new Date() });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            app.use(errorHandler);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const PORT = process.env.PORT || 5000;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            app.listen(PORT, () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              console.log(`🚀 Pathways API running on port ${PORT}`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              EOF
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              echo -e "${GREEN}✅ Server file created${NC}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              echo ""
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              # =============================================================================
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              # STEP 11: INSTALL DEPENDENCIES
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              # =============================================================================
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              echo -e "${YELLOW}[STEP 11] Installing dependencies (this may take 2-3 minutes)...${NC}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              npm install
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              echo -e "${GREEN}✅ Dependencies installed${NC}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              echo ""
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
